def tuple_to_set(tup):
    """
    Convert a tuple (or multiple tuples) into a set.

    Args:
        tup: A tuple or collection of tuples

    Returns:
        A set containing the elements
    """
    # If it's a single tuple, convert it to a set
    if isinstance(tup, tuple):
        return set(tup)
    # If it's a list/collection of tuples, flatten and convert to set
    elif isinstance(tup, (list, set)):
        result = set()
        for item in tup:
            if isinstance(item, tuple):
                result.update(item)
            else:
                result.add(item)
        return result
    else:
        return set(tup)
